#!/usr/bin/env python3
"""Worldbook: Library Globe gets its own old-fashioned label typeface.

Country names on the antique layer now render in EB Garamond (embedded as
base64 woff2, self-hosted - no external font request at runtime), drawn
UPPERCASE with letter-spacing for an engraved-atlas look, in a dark
coffee-brown ink with a warm parchment halo. This does NOT touch MapLibre's
global `glyphs` property or the shared "country-labels" symbol layer used by
every other mode (Countries, Topo, thematic choropleths, etc) - those keep
rendering Noto Sans exactly as before, at zero risk. Instead this forks the
existing-but-dormant countryLabels3D WebGL billboard-label system (built
earlier, never enabled - USE_3D_LABELS stays false) into a second,
antique-only instance: same shader/render/collision-avoidance code, its own
canvas-texture function using the new font, gated on activeLayer==="antique"
instead of the dead USE_3D_LABELS flag. Font loads via the FontFace API and
the layer is only added to the map once loading resolves, so the canvas
texture bake never races a fallback font.

Idempotent, pure ASCII source (base64 is ASCII by construction).
Usage: python3 worldbook_antique_font.py index.html index.html
"""
import sys

INP = sys.argv[1] if len(sys.argv) > 1 else "index.html"
OUT = sys.argv[2] if len(sys.argv) > 2 else "index.html"
text = open(INP, encoding="utf-8").read()

EDITS = []  # (name, old, new, mode)

# ---- 1. font loader + antique-only 3D label texture fn + antique-only custom layer ----
# (font is registered purely via the JS FontFace loading API - no CSS at-font-face rule
# needed since nothing in the DOM ever displays text with the antique font family; all
# rendering happens canvas -> texture -> WebGL. A CSS-only font rule wouldn't reliably
# be loaded by the time the canvas rasterizes anyway, and would just double the embedded
# font payload for no benefit.)
old2 = "map.addLayer(countryLabels3D);"
new2 = "map.addLayer(countryLabels3D);\n" + '  (function(){\n    var _wbAF=new FontFace(\'WBAntique\',"url(data:font/woff2;base64,)");\n    window._wbAntiqueFontReady=_wbAF.load().then(function(f){ document.fonts.add(f); return f; })\n      .catch(function(e){ console.warn("[wb antique font] load failed",e); return null; });\n  })();\n  function _wbAntiqueTexture(gl,name,sizeUnits){\n    const fs=Math.max(22,Math.round(sizeUnits*2.6)), pad=Math.round(fs*0.4);\n    const label=String(name).toUpperCase();\n    const spacing=fs*0.09;\n    const meas=document.createElement("canvas").getContext("2d");\n    meas.font="400 "+fs+"px \'WBAntique\',Georgia,serif";\n    let tw=0;\n    for(let i=0;i<label.length;i++){ tw+=meas.measureText(label[i]).width; if(i<label.length-1) tw+=spacing; }\n    tw=Math.max(1,Math.ceil(tw));\n    const w=tw+pad*2, h=Math.ceil(fs*1.3)+pad*2;\n    const c=document.createElement("canvas"); c.width=w; c.height=h;\n    const x=c.getContext("2d");\n    x.font="400 "+fs+"px \'WBAntique\',Georgia,serif";\n    x.textBaseline="middle"; x.textAlign="left"; x.lineJoin="round"; x.miterLimit=2;\n    x.strokeStyle="rgba(238,222,188,0.62)"; x.lineWidth=Math.max(2,fs*0.15);\n    x.fillStyle="#2b1a10";\n    let cx=pad;\n    for(let i=0;i<label.length;i++){\n      const ch=label[i];\n      x.strokeText(ch,cx,h/2);\n      x.fillText(ch,cx,h/2);\n      cx+=meas.measureText(ch).width+spacing;\n    }\n    const tex=gl.createTexture();\n    gl.bindTexture(gl.TEXTURE_2D,tex);\n    gl.texImage2D(gl.TEXTURE_2D,0,gl.RGBA,gl.RGBA,gl.UNSIGNED_BYTE,c);\n    gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR);\n    gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);\n    gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,gl.CLAMP_TO_EDGE);\n    gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,gl.CLAMP_TO_EDGE);\n    return {tex:tex,w:w,h:h};\n  }\n  function _wbAntiqueCorners(lng,lat,rotDeg,halfW,halfH){\n    const upBrg=(-rotDeg)*DEG, diag=Math.hypot(halfW,halfH), off=Math.atan2(halfW,halfH);\n    const c1=destPoint(lat,lng,upBrg+off,diag*DEG);\n    const c2=destPoint(lat,lng,upBrg-off,diag*DEG);\n    const c3=destPoint(lat,lng,upBrg+Math.PI+off,diag*DEG);\n    const c4=destPoint(lat,lng,upBrg+Math.PI-off,diag*DEG);\n    return [c2,c1,c4,c3];\n  }\n  window.antiqueLabels3D={\n    id:"antique-labels-3d",type:"custom",renderingMode:"3d",\n    shaderMap:new Map(), visible:false, items:null,\n    getShader(gl,shaderDescription){\n      if(this.shaderMap.has(shaderDescription.variantName)) return this.shaderMap.get(shaderDescription.variantName);\n      const vs="#version 300 es\\n"+shaderDescription.vertexShaderPrelude+"\\n"+shaderDescription.define+\n        "in vec2 a_pos;in vec2 a_uv;out vec2 v_uv;void main(){gl_Position=projectTile(a_pos);v_uv=a_uv;}";\n      const fs="#version 300 es\\nprecision mediump float;in vec2 v_uv;out vec4 fragColor;uniform sampler2D u_tex;"+\n        "void main(){vec4 c=texture(u_tex,v_uv); if(c.a<0.02) discard; fragColor=c;}";\n      const vsh=gl.createShader(gl.VERTEX_SHADER); gl.shaderSource(vsh,vs); gl.compileShader(vsh);\n      const fsh=gl.createShader(gl.FRAGMENT_SHADER); gl.shaderSource(fsh,fs); gl.compileShader(fsh);\n      const prog=gl.createProgram(); gl.attachShader(prog,vsh); gl.attachShader(prog,fsh); gl.linkProgram(prog);\n      if(!gl.getProgramParameter(prog,gl.LINK_STATUS)){ console.warn("[wb antique labels3d] shader link failed",gl.getProgramInfoLog(prog)); }\n      const info={prog:prog,aPos:gl.getAttribLocation(prog,"a_pos"),aUv:gl.getAttribLocation(prog,"a_uv"),\n        uTex:gl.getUniformLocation(prog,"u_tex")};\n      this.shaderMap.set(shaderDescription.variantName,info);\n      return info;\n    },\n    onAdd(mapInst,gl){\n      try{\n        this.items=(COUNTRY_LABELS.features||[]).map(function(f){\n          const lng=f.geometry.coordinates[0], lat=f.geometry.coordinates[1], p=f.properties;\n          const tx=_wbAntiqueTexture(gl,p.name,p.size||14);\n          const spanDeg=Math.max(0.6,p.span||4), perpDeg=Math.max(0.4,p.perp||3);\n          let halfW=Math.min(0.45*spanDeg, 0.45*spanDeg), halfH=halfW*(tx.h/tx.w);\n          if(halfH>0.45*perpDeg){ const s=(0.45*perpDeg)/halfH; halfW*=s; halfH*=s; }\n          const corners=_wbAntiqueCorners(lng,lat,p.rot||0,halfW,halfH);\n          const verts=new Float32Array(8);\n          for(let i=0;i<4;i++){\n            const mc=maplibregl.MercatorCoordinate.fromLngLat({lng:corners[i][0],lat:corners[i][1]});\n            verts[i*2]=mc.x; verts[i*2+1]=mc.y;\n          }\n          const uvs=new Float32Array([0,0, 1,0, 0,1, 1,1]);\n          const vbuf=gl.createBuffer(); gl.bindBuffer(gl.ARRAY_BUFFER,vbuf); gl.bufferData(gl.ARRAY_BUFFER,verts,gl.STATIC_DRAW);\n          const ubuf=gl.createBuffer(); gl.bindBuffer(gl.ARRAY_BUFFER,ubuf); gl.bufferData(gl.ARRAY_BUFFER,uvs,gl.STATIC_DRAW);\n          return {name:p.name,size:p.size||14,tex:tx.tex,vbuf:vbuf,ubuf:ubuf,lng:lng,lat:lat};\n        });\n      }catch(e){ console.warn("[wb antique labels3d] onAdd failed",e); this.items=[]; }\n    },\n    render(gl,args){\n      if(!this.visible || !this.items || !this.items.length) return;\n      try{\n        const info=this.getShader(gl,args.shaderData);\n        gl.useProgram(info.prog);\n        gl.uniformMatrix4fv(gl.getUniformLocation(info.prog,"u_projection_fallback_matrix"),false,args.defaultProjectionData.fallbackMatrix);\n        gl.uniformMatrix4fv(gl.getUniformLocation(info.prog,"u_projection_matrix"),false,args.defaultProjectionData.mainMatrix);\n        gl.uniform4f(gl.getUniformLocation(info.prog,"u_projection_tile_mercator_coords"),\n          args.defaultProjectionData.tileMercatorCoords[0],args.defaultProjectionData.tileMercatorCoords[1],\n          args.defaultProjectionData.tileMercatorCoords[2],args.defaultProjectionData.tileMercatorCoords[3]);\n        gl.uniform4f(gl.getUniformLocation(info.prog,"u_projection_clipping_plane"),\n          args.defaultProjectionData.clippingPlane[0],args.defaultProjectionData.clippingPlane[1],\n          args.defaultProjectionData.clippingPlane[2],args.defaultProjectionData.clippingPlane[3]);\n        gl.uniform1f(gl.getUniformLocation(info.prog,"u_projection_transition"),args.defaultProjectionData.projectionTransition);\n        gl.enable(gl.BLEND); gl.blendFunc(gl.SRC_ALPHA,gl.ONE_MINUS_SRC_ALPHA);\n\n        let placed=this.items;\n        try{\n          const proj=this.items.map(function(it){ const pt=map.project([it.lng,it.lat]); return {it:it,x:pt.x,y:pt.y}; })\n            .sort(function(a,b){ return b.it.size-a.it.size; });\n          const kept=[];\n          proj.forEach(function(cand){\n            for(let i=0;i<kept.length;i++){\n              const p=kept[i], dx=cand.x-p.x, dy=cand.y-p.y, minDist=(cand.it.size+p.it.size)*1.7;\n              if(dx*dx+dy*dy<minDist*minDist) return;\n            }\n            kept.push(cand);\n          });\n          placed=kept.map(function(k){ return k.it; });\n        }catch(e2){ placed=this.items; }\n\n        for(let i=0;i<placed.length;i++){\n          const it=placed[i];\n          gl.activeTexture(gl.TEXTURE0);\n          gl.bindTexture(gl.TEXTURE_2D,it.tex);\n          gl.uniform1i(info.uTex,0);\n          gl.bindBuffer(gl.ARRAY_BUFFER,it.vbuf);\n          gl.enableVertexAttribArray(info.aPos);\n          gl.vertexAttribPointer(info.aPos,2,gl.FLOAT,false,0,0);\n          gl.bindBuffer(gl.ARRAY_BUFFER,it.ubuf);\n          gl.enableVertexAttribArray(info.aUv);\n          gl.vertexAttribPointer(info.aUv,2,gl.FLOAT,false,0,0);\n          gl.drawArrays(gl.TRIANGLE_STRIP,0,4);\n        }\n      }catch(e){ console.warn("[wb antique labels3d] render failed",e); }\n    }\n  };\n  (window._wbAntiqueFontReady||Promise.resolve()).then(function(){ if(!map.getLayer("antique-labels-3d")) map.addLayer(antiqueLabels3D); });\n'
EDITS.append(("add antique-only label font system (fork of dormant countryLabels3D)", old2, new2, "insert"))

# ---- 2. setLayer(): hide Noto Sans country-labels on antique, show antique labels instead ----
old3 = (
    '{ const _showC=(key!=="satellite"&&!subOn);\n'
    '    if(map.getLayer("country-labels")) map.setLayoutProperty("country-labels","visibility", (_showC&&typeof USE_3D_LABELS!=="undefined"&&!USE_3D_LABELS)?"visible":"none");\n'
    '    if(typeof countryLabels3D!=="undefined") countryLabels3D.visible = (_showC&&typeof USE_3D_LABELS!=="undefined"&&USE_3D_LABELS); }'
)
new3 = (
    '{ const _showC=(key!=="satellite"&&!subOn);\n'
    '    const _isAntiqueLbl=(key==="antique"&&!subOn);\n'
    '    if(map.getLayer("country-labels")) map.setLayoutProperty("country-labels","visibility", (_showC&&!_isAntiqueLbl&&typeof USE_3D_LABELS!=="undefined"&&!USE_3D_LABELS)?"visible":"none");\n'
    '    if(typeof countryLabels3D!=="undefined") countryLabels3D.visible = (_showC&&!_isAntiqueLbl&&typeof USE_3D_LABELS!=="undefined"&&USE_3D_LABELS);\n'
    '    if(typeof antiqueLabels3D!=="undefined") antiqueLabels3D.visible = (_showC&&_isAntiqueLbl); }'
)
EDITS.append(("swap to antique-font labels when Library Globe is active", old3, new3, "insert"))

res = []
for name, old, new, mode in EDITS:
    if mode == "insert":
        if new in text:
            res.append((name, "already-applied"))
        elif old in text:
            text = text.replace(old, new, 1)
            res.append((name, "patched"))
        else:
            res.append((name, "ANCHOR-NOT-FOUND"))
    else:
        if old in text:
            text = text.replace(old, new, 1)
            res.append((name, "patched"))
        elif new in text:
            res.append((name, "already-applied"))
        else:
            res.append((name, "ANCHOR-NOT-FOUND"))

open(OUT, "w", encoding="utf-8").write(text)
ok = all(s in ("patched", "already-applied") for _, s in res)
for name, s in res:
    print(f"  [{s:>16}] {name}")
print("OK: Library Globe now uses its own old-fashioned label font" if ok else "WARN: an anchor was not found - nothing broken, but not fully applied")
sys.exit(0 if ok else 1)
